// Email Content Processing
// Xử lý nội dung email

const email = $input.first().json;
const content = email.snippet || email.body || '';
const subject = email.subject || '';
const sender = email.from || '';

// Extract email address from sender
const emailMatch = sender.match(/<(.+?)>/);
const senderEmail = emailMatch ? emailMatch[1] : sender;

// Check for complaint keywords
const complaintKeywords = [
  'phàn nàn', 'khiếu nại', 'không hài lòng', 'thất vọng', 
  'lỗi', 'sự cố', 'vấn đề', 'complaint', 'unhappy', 'disappointed',
  'problem', 'issue', 'error', 'bug', 'broken', 'not working'
];

const hasComplaintKeyword = complaintKeywords.some(keyword => 
  content.toLowerCase().includes(keyword.toLowerCase()) ||
  subject.toLowerCase().includes(keyword.toLowerCase())
);

return {
  emailId: email.id,
  senderEmail: senderEmail,
  subject: subject,
  content: content,
  receivedAt: email.date || new Date().toISOString(),
  hasComplaintKeyword: hasComplaintKeyword,
  originalEmail: email
};

// Ollama Email Analysis
// Phân tích email với Ollama

const { spawn } = require('child_process');
const http = require('http');

const email = $input.first().json;

// Function to call Ollama API
async function callOllama(prompt) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify({
      model: 'llama3.2',
      prompt: prompt,
      stream: false,
      temperature: 0.3,
      top_p: 0.9,
      max_tokens: 500
    });

    const options = {
      hostname: 'localhost',
      port: 11434,
      path: '/api/generate',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': data.length
      }
    };

    const req = http.request(options, (res) => {
      let responseData = '';

      res.on('data', (chunk) => {
        responseData += chunk;
      });

      res.on('end', () => {
        try {
          const response = JSON.parse(responseData);
          resolve(response);
        } catch (error) {
          reject(error);
        }
      });
    });

    req.on('error', (error) => {
      reject(error);
    });

    req.write(data);
    req.end();
  });
}

// Function to check if Ollama is running
async function checkOllama() {
  return new Promise((resolve) => {
    const req = http.request({
      hostname: 'localhost',
      port: 11434,
      path: '/api/tags',
      method: 'GET',
      timeout: 5000
    }, (res) => {
      resolve(res.statusCode === 200);
    });

    req.on('error', () => {
      resolve(false);
    });

    req.on('timeout', () => {
      req.destroy();
      resolve(false);
    });

    req.end();
  });
}

// Main analysis function
async function analyzeEmail() {
  try {
    // Check if Ollama is running
    const isOllamaRunning = await checkOllama();

    if (!isOllamaRunning) {
      console.log('Ollama is not running. Using fallback analysis.');
      return fallbackAnalysis();
    }

    // Create analysis prompt
    const prompt = `Analyze the following email and determine if it's a complaint. Provide a JSON response with:
1. is_complaint (boolean)
2. complaint_category (string: service_quality, product_issue, billing, technical, other)
3. sentiment_score (float: -1 to 1, where negative indicates complaint)
4. urgency_level (string: low, medium, high)
5. key_issues (array of strings, maximum 3 items)

Email:
Subject: ${email.subject}
From: ${email.senderEmail}
Content: ${email.content}

Respond only with valid JSON. No additional text.`;

    // Call Ollama
    const response = await callOllama(prompt);
    const responseText = response.response || '';

    // Extract JSON from response
    const jsonMatch = responseText.match(/\{[^}]+\}/s);
    if (jsonMatch) {
      try {
        const result = JSON.parse(jsonMatch[0]);
        return {
          is_complaint: Boolean(result.is_complaint),
          complaint_category: result.complaint_category || 'other',
          sentiment_score: parseFloat(result.sentiment_score) || 0.0,
          urgency_level: result.urgency_level || 'medium',
          key_issues: Array.isArray(result.key_issues) ? result.key_issues.slice(0, 3) : [],
          analysis_method: 'ollama'
        };
      } catch (parseError) {
        console.log('Failed to parse Ollama response, using fallback');
        return fallbackAnalysis();
      }
    } else {
      console.log('No JSON found in Ollama response, using fallback');
      return fallbackAnalysis();
    }

  } catch (error) {
    console.log('Error calling Ollama:', error.message);
    return fallbackAnalysis();
  }
}

// Fallback analysis function
function fallbackAnalysis() {
  const text = (email.subject + ' ' + email.content).toLowerCase();

  // Complaint keywords
  const complaintKeywords = [
    'phàn nàn', 'khiếu nại', 'không hài lòng', 'thất vọng',
    'lỗi', 'sự cố', 'vấn đề', 'complaint', 'unhappy', 'disappointed',
    'problem', 'issue', 'error', 'bug', 'broken', 'not working'
  ];

  const isComplaint = complaintKeywords.some(keyword => text.includes(keyword));

  // Category detection
  let category = 'other';
  if (/dịch vụ|service|hỗ trợ|support/.test(text)) {
    category = 'service_quality';
  } else if (/sản phẩm|product|hàng|item/.test(text)) {
    category = 'product_issue';
  } else if (/thanh toán|payment|hóa đơn|invoice/.test(text)) {
    category = 'billing';
  } else if (/kỹ thuật|technical|hệ thống|system/.test(text)) {
    category = 'technical';
  }

  // Simple sentiment
  const positiveWords = ['tốt', 'hay', 'hài lòng', 'good', 'great', 'happy'];
  const negativeWords = ['xấu', 'kém', 'tệ', 'không hài lòng', 'bad', 'poor', 'unhappy'];

  const posCount = positiveWords.filter(word => text.includes(word)).length;
  const negCount = negativeWords.filter(word => text.includes(word)).length;

  const sentiment = (posCount - negCount) / Math.max(text.split(' ').length, 1) * 10;
  const finalSentiment = Math.max(-1.0, Math.min(1.0, sentiment));

  return {
    is_complaint: isComplaint,
    complaint_category: category,
    sentiment_score: finalSentiment,
    urgency_level: 'medium',
    key_issues: ['keyword_analysis_fallback'],
    analysis_method: 'fallback'
  };
}

// Execute analysis
const analysisResult = await analyzeEmail();

return {
  ...email,
  ...analysisResult,
  analyzedAt: new Date().toISOString()
};

// Ollama Response Generation
// Tạo phản hồi với Ollama

const http = require('http');

const complaint = $input.first().json;

// Function to call Ollama API
async function callOllama(prompt) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify({
      model: 'llama3.2',
      prompt: prompt,
      stream: false,
      temperature: 0.7,
      top_p: 0.9,
      max_tokens: 400
    });

    const options = {
      hostname: 'localhost',
      port: 11434,
      path: '/api/generate',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': data.length
      }
    };

    const req = http.request(options, (res) => {
      let responseData = '';

      res.on('data', (chunk) => {
        responseData += chunk;
      });

      res.on('end', () => {
        try {
          const response = JSON.parse(responseData);
          resolve(response);
        } catch (error) {
          reject(error);
        }
      });
    });

    req.on('error', (error) => {
      reject(error);
    });

    req.write(data);
    req.end();
  });
}

// Function to check if Ollama is running
async function checkOllama() {
  return new Promise((resolve) => {
    const req = http.request({
      hostname: 'localhost',
      port: 11434,
      path: '/api/tags',
      method: 'GET',
      timeout: 5000
    }, (res) => {
      resolve(res.statusCode === 200);
    });

    req.on('error', () => {
      resolve(false);
    });

    req.on('timeout', () => {
      req.destroy();
      resolve(false);
    });

    req.end();
  });
}

// Main response generation
async function generateResponse() {
  try {
    // Check if Ollama is running
    const isOllamaRunning = await checkOllama();

    if (!isOllamaRunning) {
      console.log('Ollama is not running. Using fallback response.');
      return fallbackResponse();
    }

    // Create response prompt
    const prompt = `You are a customer service representative. Generate a professional and empathetic response in Vietnamese for this customer complaint.

Complaint Details:
- Category: ${complaint.complaint_category}
- Sentiment: ${complaint.sentiment_score.toFixed(2)}
- Urgency: ${complaint.urgency_level}
- Key Issues: ${complaint.key_issues.join(', ')}

Original Email:
Subject: ${complaint.subject}
Content: ${complaint.content}

Requirements:
1. Acknowledge the issue
2. Apologize for the inconvenience  
3. Explain next steps
4. Provide timeline for resolution
5. Include contact information for follow-up
6. Keep it professional and empathetic
7. Response should be 150-250 words
8. Write in Vietnamese

Generate the response:`;

    // Call Ollama
    const response = await callOllama(prompt);
    const responseText = response.response || '';

    // Clean and return response
    const cleanedResponse = responseText.trim();

    if (cleanedResponse.length > 50) {
      return {
        response_content: cleanedResponse,
        response_tone: 'professional',
        confidence_score: 0.8,
        generation_method: 'ollama'
      };
    } else {
      console.log('Ollama response too short, using fallback');
      return fallbackResponse();
    }

  } catch (error) {
    console.log('Error calling Ollama:', error.message);
    return fallbackResponse();
  }
}

// Fallback response function
function fallbackResponse() {
  const templates = {
    'service_quality': `Kính gửi Quý khách,\n\nChúng tôi đã nhận được phản hồi của Quý khách về dịch vụ và rất tiếc về trải nghiệm không tốt. Chúng tôi xin chân thành xin lỗi về sự bất tiện này.\n\nChúng tôi đã ghi nhận khiếu nại của Quý khách và sẽ xem xét lại quy trình dịch vụ để cải thiện chất lượng. Quý khách sẽ nhận được phản hồi chi tiết trong vòng 24 giờ.\n\nCảm ơn Quý khách đã thông báo cho chúng tôi.\n\nTrân trọng,\nĐội ngũ hỗ trợ khách hàng`,

    'product_issue': `Kính gửi Quý khách,\n\nChúng tôi đã nhận được thông báo về vấn đề với sản phẩm của Quý khách. Chúng tôi rất tiếc về sự cố này và xin lỗi Quý khách vì trải nghiệm không tốt.\n\nChúng tôi sẽ tiến hành kiểm tra sản phẩm và cung cấp giải pháp thay thế nếu cần. Trong vòng 48 giờ, chúng tôi sẽ liên hệ với Quý khách để hướng dẫn các bước tiếp theo.\n\nCảm ơn sự kiên nhẫn của Quý khách.\n\nTrân trọng,\nĐội ngũ kỹ thuật`,

    'billing': `Kính gửi Quý khách,\n\nChúng tôi đã nhận được khiếu nại của Quý khách về vấn đề thanh toán. Chúng tôi xin lỗi về sự nhầm lẫn trong quá trình thanh toán.\n\nKế toán của chúng tôi sẽ kiểm tra lại giao dịch và xử lý theo quy định. Vấn đề sẽ được giải quyết trong vòng 24 giờ làm việc.\n\nCảm ơn Quý khách đã thông báo cho chúng tôi.\n\nTrân trọng,\nBộ phận kế toán`,

    'technical': `Kính gửi Quý khách,\n\nChúng tôi đã nhận được báo cáo về vấn đề kỹ thuật của Quý khách. Chúng tôi xin lỗi về sự cố kỹ thuật này.\n\nĐội ngũ kỹ thuật của chúng tôi đang điều tra và khắc phục vấn đề. Quý khách sẽ được thông báo khi vấn đề được giải quyết.\n\nCảm ơn sự thông cảm của Quý khách.\n\nTrân trọng,\nĐội ngũ kỹ thuật`,

    'other': `Kính gửi Quý khách,\n\nChúng tôi đã nhận được thông tin từ Quý khách và rất ghi nhận phản hồi này. Chúng tôi sẽ xem xét kỹ lưỡng nội dung Quý khách đã gửi.\n\nChúng tôi sẽ liên hệ lại với Quý khách trong thời gian sớm nhất để cung cấp thông tin chi tiết.\n\nCảm ơn Quý khách đã liên hệ.\n\nTrân trọng,\nĐội ngũ hỗ trợ`
  };

  const category = complaint.complaint_category || 'other';
  const template = templates[category] || templates.other;

  return {
    response_content: template,
    response_tone: 'professional',
    confidence_score: 0.6,
    generation_method: 'fallback'
  };
}

// Execute response generation
const responseResult = await generateResponse();

return {
  ...complaint,
  ...responseResult,
  generated_at: new Date().toISOString()
};

